import fs from "fs/promises";
import path from "path";
import Link from "next/link";
import CheckMyDate from "@/components/CheckMyDate"; // <-- 1. We import the calculator here

type EventRecord = {
  category?: string;
};

async function loadEvents(): Promise<EventRecord[]> {
  const jsonPath = path.resolve(process.cwd(), "data/events.json");
  const raw = await fs.readFile(jsonPath, "utf8");
  const parsed = JSON.parse(raw);
  if (!Array.isArray(parsed)) return [];
  return parsed.filter(Boolean) as EventRecord[];
}

export default async function HomePage() {
  const events = await loadEvents();

  // The strict TypeScript fix is applied here:
  const categories = Array.from(
    new Set(
      events
        .map((e) => e.category)
        .filter((c): c is string => typeof c === "string" && c.trim().length > 0)
    )
  );

  return (
    <main className="mx-auto max-w-3xl px-5 py-12">
      <h1 className="text-3xl font-semibold tracking-tight">
        When Is Due?
      </h1>

      <p className="mt-3 text-sm opacity-70">
        Verified countdowns for major events.
      </p>

      {/* <-- 2. We inject the calculator right here so it sits above your categories */}
      <div className="mt-8 mb-12">
        <CheckMyDate />
      </div>

      <div className="mt-10 space-y-3">
        {categories.map((cat) => (
          <Link
            key={cat}
            href={`/${cat}`}
            className="block rounded-xl border border-white/10 bg-white/[0.03] px-4 py-4 hover:bg-white/[0.05] transition"
          >
            <div className="text-lg font-semibold capitalize">
              {cat.replace(/-/g, " ")}
            </div>
          </Link>
        ))}
      </div>
    </main>
  );
}